import React from 'react';
import type { CSSProperties } from 'react';
import type { ErpDataListGridProps } from '@linm-soft/common-components';
import { CatalogListGrid } from '../CatalogListGrid';
import { CatalogSchemaCell } from './CatalogSchemaCell';
import { resolveCatalogRowCellStyle } from './resolveCatalogRowCellStyle';
import type { CatalogUiField, CatalogUiSchema } from '../../../types/catalogUiSchema';
import type { UseCatalogListSelectionResult } from '../../../hooks/useCatalogListSelection';
import { catalogListTableConfigFromSchema } from '../catalogListTableConfig';

type CatalogListGridFromSchemaBaseProps<T> = Pick<
  ErpDataListGridProps<T>,
  | 'getRowEditBlockedMessage'
  | 'rowEditHintDismissStorageKey'
  | 'onRowOpenActionMenu'
  | 'rowMenuHintMessage'
  | 'rowMenuHintDismissStorageKey'
  | 'enableRowMenuLongPress'
>;

export type ErpListSortState = { columnKey: string; direction: 'asc' | 'desc' } | null;

export interface CatalogListGridFromSchemaProps<T>
  extends CatalogListGridFromSchemaBaseProps<T> {
  testIdPrefix: string;
  rows: T[];
  page: number;
  pageSize: number;
  columns: CatalogUiField[];
  schema?: CatalogUiSchema | null;
  selection: UseCatalogListSelectionResult<T>;
  getRowId: (row: T) => string;
  isRowSelectable?: (row: T) => boolean;
  /** When set, indents the code column: (depth - 1) * treeIndentPx. */
  getTreeRowDepth?: (row: T) => number;
  treeIndentPx?: number;
  /** Row cell colors — defaults to BE `fontColor` / `backgroundColor` on row. */
  getRowCellStyle?: (row: T) => CSSProperties | undefined;
}

export function CatalogListGridFromSchema<T>({
  testIdPrefix,
  rows,
  page,
  pageSize,
  columns,
  schema,
  selection,
  getRowId,
  isRowSelectable,
  getTreeRowDepth,
  treeIndentPx: indentStepPx = 16,
  getRowCellStyle,
  getRowEditBlockedMessage,
  rowEditHintDismissStorageKey,
  onRowOpenActionMenu,
  rowMenuHintMessage,
  rowMenuHintDismissStorageKey,
  enableRowMenuLongPress,
}: CatalogListGridFromSchemaProps<T>): React.ReactElement {
  const columnDefs = columns.map(col => ({
    key: col.key,
    label: col.label,
    width: col.list?.width,
  }));

  const resolveRowStyle = (row: T): CSSProperties | undefined =>
    getRowCellStyle?.(row)
    ?? resolveCatalogRowCellStyle(row as unknown as Record<string, unknown>);

  return (
    <CatalogListGrid
      testIdPrefix={testIdPrefix}
      rows={rows}
      page={page}
      pageSize={pageSize}
      selection={selection}
      getRowId={getRowId}
      isRowSelectable={isRowSelectable}
      getRowEditBlockedMessage={getRowEditBlockedMessage}
      rowEditHintDismissStorageKey={rowEditHintDismissStorageKey}
      onRowOpenActionMenu={onRowOpenActionMenu}
      rowMenuHintMessage={rowMenuHintMessage}
      rowMenuHintDismissStorageKey={rowMenuHintDismissStorageKey}
      enableRowMenuLongPress={enableRowMenuLongPress}
      columnDefs={columnDefs}
      tableConfig={catalogListTableConfigFromSchema(schema?.list)}
      headerCells={(
        <>
          {columns.map(col => (
            <th key={col.key}>{col.label}</th>
          ))}
        </>
      )}
      renderRow={row => {
        const treeDepth = getTreeRowDepth?.(row);
        const codeIndentPx =
          treeDepth != null && treeDepth > 1
            ? Math.max(0, treeDepth - 1) * indentStepPx
            : undefined;
        const cellStyle = resolveRowStyle(row);
        return (
          <>
            {columns.map(col => (
              <CatalogSchemaCell
                key={col.key}
                field={col}
                row={row as unknown as Record<string, unknown>}
                testIdPrefix={testIdPrefix}
                codeIndentPx={col.key === 'code' ? codeIndentPx : undefined}
                cellStyle={cellStyle}
              />
            ))}
          </>
        );
      }}
    />
  );
}
